Dear all!

I struggling with using this lib for my project.

I want to put the Server in a Class, because I will add quite a lot of methods and variables in it. I also need member variables (in the example: self.factor). However, I am struggling with the SELF-keyword that is the first parameter of class methods in combination with dispatching methods with json-rpc

My Server:

``
from werkzeug.wrappers import Request, Response
from werkzeug.serving import run_simple

from jsonrpc import JSONRPCResponseManager, dispatcher


class LEDServer:
    def __init__(self):
        self.factor = 3
        run_simple('localhost', 8910, self.start_server)

    @Request.application
    def start_server(self, request):
        response = JSONRPCResponseManager.handle(request.data, dispatcher)
        return Response(response.json, mimetype='application/json')

    @dispatcher.add_method
    def bar(**kwargs):
        print(str(kwargs["a"])+' + '+str(kwargs["b"])+' = '+str(kwargs["a"]+kwargs["b"]))
        return {"c" : kwargs["a"]+kwargs["b"]}

    @dispatcher.add_method
    def panel_on(self, **kwargs):
        print(str(kwargs["a"] * self.factor)+' + '+str(kwargs["b"])+' = '+str(kwargs["a"]+kwargs["b"]))
        return {"c" : kwargs["a"]+kwargs["b"]}



if __name__ == '__main__':
    s=LEDServer()

``

My Client:

``

import requests
import json


def rpc_call(url, method, params):
    """ do remote procedure call """
    headers = {'content-type': 'application/json'}
    payload = {
        "method": method,
        "params": params,
        "jsonrpc": "2.0",
        "id": 0,
    }
    try:
        response = requests.post(url, data=json.dumps(payload), headers=headers, timeout=2000).json()

    except (requests.Timeout, requests.ConnectionError):
        print('Error: Skill server not responding')
        response = 0;
        # skill server not responding

    return response


if __name__ == '__main__':


    params={'a':2,'b':6}
    print(rpc_call('http://localhost:8910', method='bar', params=params))

    params={'a':2,'b':6}
    print(rpc_call('http://localhost:8910', method='panel_on', params=params))
''

The error:

`{'result': {'c': 8}, 'id': 0, 'jsonrpc': '2.0'}
{'error': {'code': -32602, 'message': 'Invalid params', 'data': {'type': 'TypeError', 'args': ["panel_on() missing 1 required positional argument: 'self'"], 'message': "panel_on() missing 1 required positional argument: 'self'"}}, 'id': 0, 'jsonrpc': '2.0'}
`

So obviously the SELF-paramter of the panel_on() method is not present....which is natural. Do you know ways to solve that isssue?

Thanks in advance for any help.

Best
Anton

