if a field has an `attribute` set on it, then there is no way to use the decorator `@validates` to validate the field. see the following test cases:

```python
from marshmallow import Schema, fields, ValidationError, validates

class Broken(Schema):
    s = fields.String(attribute='string_name')

    @validates('s')
    def validate_string(self, data):
        raise ValidationError('nope')

class Broken2(Schema):
    s = fields.String(attribute='string_name')

    @validates('string_name')
    def validate_string(self, data):
        raise ValidationError('nope')

class Working(Schema):
    s = fields.String()

    @validates('s')
    def validate_string(self, data):
        raise ValidationError('nope')

Broken(strict=True).load({'s': 'hello'}) # does not throw validation error
Broken2(strict=True).load({'s': 'hello'}) # complains that 'string_name' field doesn't exist
Working(strict=True).load({'s': 'hello'}) # works (i.e., raises ValidationError)
```

Currently, if we were to run the library with Python3.6, we will have this error:
  File "C:\Python36\lib\site-packages\pyotp\otp.py", line 49, in byte_secret
    self.secret += '=' * (8 - missing_padding)
TypeError: can't concat str to bytes

By simple change of the code in otp.py, will make it work:
    def byte_secret(self):
        missing_padding = len(self.secret) % 8
        if missing_padding != 0:
            **self.secret += b'=' * (8 - missing_padding)**
        return base64.b32decode(self.secret, casefold=True)

Hi,

I'm trying to build Python bindings for a project `libcaer` with `pybind11`.
Quickly I'm running into this problem of wrapping namespace functions.
The file is here: https://github.com/duguyue100/libcaer/blob/master/includecpp/libcaer.hpp

```c++
#ifndef LIBCAER_HPP_
#define LIBCAER_HPP_

#include <pybind11/pybind11.h>
#include <libcaer/libcaer.h>
#include <stdexcept>
#include <type_traits>

namespace py = pybind11;
namespace libcaer {
namespace log {

// Undefine the log-level names, to avoid conflicts with macros
// on Windows/MinGW for example.
#undef EMERGENCY
#undef ALERT
#undef CRITICAL
#undef ERROR
#undef WARNING
#undef NOTICE
#undef INFO
#undef DEBUG

enum class logLevel {
	EMERGENCY = 0,
	ALERT = 1,
	CRITICAL = 2,
	ERROR = 3,
	WARNING = 4,
	NOTICE = 5,
	INFO = 6,
	DEBUG = 7,
};

inline void logLevelSet(logLevel l) noexcept;
inline logLevel logLevelGet() noexcept;
inline void fileDescriptorsSet(int fd1, int fd2) noexcept;
inline int fileDescriptorsGetFirst() noexcept;
inline int fileDescriptorsGetSecond() noexcept;
inline void log(logLevel l, const char *subSystem, const char *format, ...) noexcept;
inline void logVA(logLevel l, const char *subSystem, const char *format, va_list args) noexcept;
inline void logVAFull(int logFileDescriptor1, int logFileDescriptor2, uint8_t systemLogLevel, logLevel l,
	const char *subSystem, const char *format, va_list args) noexcept;

inline void logLevelSet(logLevel l) noexcept {
	caerLogLevelSet(static_cast<enum caer_log_level>(static_cast<typename std::underlying_type<logLevel>::type>(l)));
}

inline logLevel logLevelGet() noexcept {
	return (static_cast<logLevel>(caerLogLevelGet()));
}

inline void fileDescriptorsSet(int fd1, int fd2) noexcept {
	caerLogFileDescriptorsSet(fd1, fd2);
}

inline int fileDescriptorsGetFirst() noexcept {
	return (caerLogFileDescriptorsGetFirst());
}

inline int fileDescriptorsGetSecond() noexcept {
	return (caerLogFileDescriptorsGetSecond());
}

inline void log(logLevel l, const char *subSystem, const char *format, ...) noexcept {
	va_list argumentList;
	va_start(argumentList, format);
	caerLogVA(static_cast<enum caer_log_level>(static_cast<typename std::underlying_type<logLevel>::type>(l)),
		subSystem, format, argumentList);
	va_end(argumentList);
}

inline void logVA(logLevel l, const char *subSystem, const char *format, va_list args) noexcept {
	caerLogVA(static_cast<enum caer_log_level>(static_cast<typename std::underlying_type<logLevel>::type>(l)),
		subSystem, format, args);
}

inline void logVAFull(int logFileDescriptor1, int logFileDescriptor2, uint8_t systemLogLevel, logLevel l,
	const char *subSystem, const char *format, va_list args) noexcept {
	caerLogVAFull(logFileDescriptor1, logFileDescriptor2, systemLogLevel,
		static_cast<enum caer_log_level>(static_cast<typename std::underlying_type<logLevel>::type>(l)), subSystem,
		format, args);
}

}
}

#endif /* LIBCAER_HPP_ */
```

I've searched around and I don't know how to do it. Should I wrap it as a class? and if so, because the namespace `log` is in the namespace `libcaer`, how should I do it?

I'm really appreciate that someone here can provide your advices.

Regards,
Yuhuang.

I'm struggling to get this working with requireJS. I've tried the examples in the README with no luck.

Here is my control case:

```` javascript
define([
  'require',
  'jquery',
  'mustache',
  'js-yaml.min',
], function(require, $){

  var JB = { 
    init : function(boot){
      var doc = jsyaml.load('greeting: hello\nname: world');
      console.log(doc); // this works fine.
      
      //require('js-yaml.min'); // this works both uncommented and commented.
      
      var singleDoc = require('http://127.0.0.1/~jade/javascripts/require-js/tags.yaml').shift();
      console.log(singleDoc); 
      // This does not work
      // Uncaught Error: Module name 'http://127.0.0.1/~jade/javascripts/require-js/tags.yaml' has not been loaded yet for context: _
      // http://requirejs.org/docs/errors.html#notloaded

      if(typeof boot === "function") boot();
    } 
  };

  return JB;
});
````

As per the error documentation (<http://requirejs.org/docs/errors.html#notloaded>) I have tried to load the tags.yaml first in the define statement. The tags.yaml loads fine but since its not javascript, It returns a syntax error.

Any help would be appreciated, thanks.
